from flask import Flask, request, jsonify
import os
import io
import uuid
import json
import threading
from datetime import datetime

import numpy as np
import pandas as pd
from PIL import Image
import tensorflow as tf

app = Flask(__name__)

BASE_DIR = os.environ.get("ML_PIPELINE_DIR", "./ml_pipeline_data")
UPLOAD_DIR = os.path.join(BASE_DIR, "uploads")
DATA_DIR = os.path.join(BASE_DIR, "data")
MODEL_DIR = os.path.join(BASE_DIR, "model")
META_PATH = os.path.join(BASE_DIR, "metadata.json")
CSV_DATA_PATH = os.path.join(DATA_DIR, "tabular.csv")
IMAGE_LABELS_PATH = os.path.join(DATA_DIR, "image_labels.json")
LOCK = threading.Lock()

os.makedirs(UPLOAD_DIR, exist_ok=True)
os.makedirs(DATA_DIR, exist_ok=True)
os.makedirs(MODEL_DIR, exist_ok=True)

if not os.path.exists(META_PATH):
    with open(META_PATH, "w", encoding="utf-8") as f:
        json.dump({"uploads": [], "last_training": None, "model_type": None}, f)


def load_metadata():
    with open(META_PATH, "r", encoding="utf-8") as f:
        return json.load(f)


def save_metadata(meta):
    with open(META_PATH, "w", encoding="utf-8") as f:
        json.dump(meta, f, indent=2)


def append_csv_rows(df):
    if os.path.exists(CSV_DATA_PATH):
        existing = pd.read_csv(CSV_DATA_PATH)
        combined = pd.concat([existing, df], ignore_index=True)
    else:
        combined = df
    combined.to_csv(CSV_DATA_PATH, index=False)


def load_image_labels():
    if os.path.exists(IMAGE_LABELS_PATH):
        with open(IMAGE_LABELS_PATH, "r", encoding="utf-8") as f:
            return json.load(f)
    return []


def save_image_labels(records):
    with open(IMAGE_LABELS_PATH, "w", encoding="utf-8") as f:
        json.dump(records, f, indent=2)


def load_image_dataset(records, image_size=(128, 128), batch_size=32):
    paths = [r["path"] for r in records]
    labels = [r["label"] for r in records]
    class_names = sorted(list(set(labels)))
    class_to_idx = {name: i for i, name in enumerate(class_names)}
    y = np.array([class_to_idx[l] for l in labels], dtype=np.int32)

    def read_image(path, label):
        image = tf.io.read_file(path)
        image = tf.image.decode_image(image, channels=3, expand_animations=False)
        image = tf.image.resize(image, image_size)
        image = tf.cast(image, tf.float32) / 255.0
        return image, label

    ds = tf.data.Dataset.from_tensor_slices((paths, y))
    ds = ds.shuffle(buffer_size=len(paths), reshuffle_each_iteration=True)
    ds = ds.map(read_image, num_parallel_calls=tf.data.AUTOTUNE)
    ds = ds.batch(batch_size).prefetch(tf.data.AUTOTUNE)
    return ds, class_names


def build_image_model(num_classes, input_shape=(128, 128, 3)):
    base = tf.keras.applications.MobileNetV2(
        input_shape=input_shape,
        include_top=False,
        weights="imagenet"
    )
    base.trainable = False
    model = tf.keras.Sequential([
        tf.keras.layers.Input(shape=input_shape),
        base,
        tf.keras.layers.GlobalAveragePooling2D(),
        tf.keras.layers.Dropout(0.2),
        tf.keras.layers.Dense(num_classes, activation="softmax")
    ])
    model.compile(
        optimizer=tf.keras.optimizers.Adam(learning_rate=1e-3),
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"]
    )
    return model


def build_tabular_model(input_dim, num_classes=2):
    model = tf.keras.Sequential([
        tf.keras.layers.Input(shape=(input_dim,)),
        tf.keras.layers.Dense(64, activation="relu"),
        tf.keras.layers.Dropout(0.2),
        tf.keras.layers.Dense(32, activation="relu"),
        tf.keras.layers.Dense(num_classes, activation="softmax")
    ])
    model.compile(
        optimizer=tf.keras.optimizers.Adam(learning_rate=1e-3),
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"]
    )
    return model


def train_image_model():
    records = load_image_labels()
    if len(records) < 2:
        return {"status": "error", "message": "Not enough image samples to train."}
    ds, class_names = load_image_dataset(records)
    model = build_image_model(len(class_names))
    model.fit(ds, epochs=5, verbose=0)
    model_path = os.path.join(MODEL_DIR, "image_model")
    model.save(model_path, include_optimizer=False)
    with LOCK:
        meta = load_metadata()
        meta["last_training"] = datetime.utcnow().isoformat() + "Z"
        meta["model_type"] = "image"
        meta["class_names"] = class_names
        save_metadata(meta)
    return {"status": "ok", "model_path": model_path, "classes": class_names}


def train_tabular_model():
    if not os.path.exists(CSV_DATA_PATH):
        return {"status": "error", "message": "No CSV dataset found."}
    df = pd.read_csv(CSV_DATA_PATH)
    if "label" not in df.columns:
        return {"status": "error", "message": "CSV must contain a 'label' column."}
    df = df.dropna()
    y_raw = df["label"].astype(str)
    x_df = df.drop(columns=["label"])
    x_df = pd.get_dummies(x_df)
    class_names = sorted(y_raw.unique().tolist())
    class_to_idx = {c: i for i, c in enumerate(class_names)}
    y = y_raw.map(class_to_idx).astype(np.int32).values
    x = x_df.values.astype(np.float32)
    model = build_tabular_model(x.shape[1], len(class_names))
    model.fit(x, y, epochs=10, batch_size=32, verbose=0)
    model_path = os.path.join(MODEL_DIR, "tabular_model")
    model.save(model_path, include_optimizer=False)
    with LOCK:
        meta = load_metadata()
        meta["last_training"] = datetime.utcnow().isoformat() + "Z"
        meta["model_type"] = "tabular"
        meta["class_names"] = class_names
        meta["feature_columns"] = x_df.columns.tolist()
        save_metadata(meta)
    return {"status": "ok", "model_path": model_path, "classes": class_names}


@app.route("/upload/csv", methods=["POST"])
def upload_csv():
    if "file" not in request.files:
        return jsonify({"status": "error", "message": "Missing file"}), 400
    f = request.files["file"]
    if not f.filename.lower().endswith(".csv"):
        return jsonify({"status": "error", "message": "Only CSV files allowed"}), 400
    df = pd.read_csv(f)
    if "label" not in df.columns:
        return jsonify({"status": "error", "message": "CSV must contain a 'label' column"}), 400
    append_csv_rows(df)
    upload_id = str(uuid.uuid4())
    save_path = os.path.join(UPLOAD_DIR, f"{upload_id}.csv")
    f.stream.seek(0)
    f.save(save_path)
    with LOCK:
        meta = load_metadata()
        meta["uploads"].append({"id": upload_id, "type": "csv", "filename": f.filename, "timestamp": datetime.utcnow().isoformat() + "Z"})
        save_metadata(meta)
    return jsonify({"status": "ok", "upload_id": upload_id})


@app.route("/upload/image", methods=["POST"])
def upload_image():
    if "file" not in request.files or "label" not in request.form:
        return jsonify({"status": "error", "message": "Missing file or label"}), 400
    f = request.files["file"]
    label = request.form["label"].strip()
    try:
        img = Image.open(f.stream).convert("RGB")
    except Exception:
        return jsonify({"status": "error", "message": "Invalid image"}), 400
    upload_id = str(uuid.uuid4())
    filename = f"{upload_id}_{secure_name(f.filename)}"
    save_path = os.path.join(UPLOAD_DIR, filename)
    img.save(save_path)
    records = load_image_labels()
    records.append({"path": save_path, "label": label, "timestamp": datetime.utcnow().isoformat() + "Z"})
    save_image_labels(records)
    with LOCK:
        meta = load_metadata()
        meta["uploads"].append({"id": upload_id, "type": "image", "filename": f.filename, "label": label, "timestamp": datetime.utcnow().isoformat() + "Z"})
        save_metadata(meta)
    return jsonify({"status": "ok", "upload_id": upload_id})


def secure_name(name):
    keep = []
    for ch in os.path.basename(name):
        if ch.isalnum() or ch in (".", "_", "-"):
            keep.append(ch)
        else:
            keep.append("_")
    return "".join(keep)[:255] or "upload"


@app.route("/train", methods=["POST"])
def train():
    payload = request.get_json(silent=True) or {}
    model_type = payload.get("model_type", "image")
    with LOCK:
        if model_type == "image":
            result = train_image_model()
        elif model_type == "tabular":
            result = train_tabular_model()
        else:
            return jsonify({"status": "error", "message": "Invalid model_type"}), 400
    status_code = 200 if result.get("status") == "ok" else 400
    return jsonify(result), status_code


@app.route("/predict/image", methods=["POST"])
def predict_image():
    model_path = os.path.join(MODEL_DIR, "image_model")
    if not os.path.exists(model_path):
        return jsonify({"status": "error", "message": "Image model not trained"}), 400
    if "file" not in request.files:
        return jsonify({"status": "error", "message": "Missing file"}), 400
    meta = load_metadata()
    class_names = meta.get("class_names", [])
    if not class_names:
        return jsonify({"status": "error", "message": "Class metadata missing"}), 400
    model = tf.keras.models.load_model(model_path)
    f = request.files["file"]
    img = Image.open(f.stream).convert("RGB").resize((128, 128))
    x = np.array(img, dtype=np.float32) / 255.0
    x = np.expand_dims(x, axis=0)
    preds = model.predict(x, verbose=0)[0]
    idx = int(np.argmax(preds))
    return jsonify({"status": "ok", "prediction": class_names[idx], "confidence": float(preds[idx]), "scores": {class_names[i]: float(preds[i]) for i in range(len(class_names))}})


@app.route("/predict/tabular", methods=["POST"])
def predict_tabular():
    model_path = os.path.join(MODEL_DIR, "tabular_model")
    if not os.path.exists(model_path):
        return jsonify({"status": "error", "message": "Tabular model not trained"}), 400
    payload = request.get_json(force=True, silent=False)
    meta = load_metadata()
    feature_columns = meta.get("feature_columns", [])
    class_names = meta.get("class_names", [])
    if not feature_columns or not class_names:
        return jsonify({"status": "error", "message": "Model metadata missing"}), 400
    row = pd.DataFrame([payload])
    row = pd.get_dummies(row)
    row = row.reindex(columns=feature_columns, fill_value=0)
    x = row.values.astype(np.float32)
    model = tf.keras.models.load_model(model_path)
    preds = model.predict(x, verbose=0)[0]
    idx = int(np.argmax(preds))
    return jsonify({"status": "ok", "prediction": class_names[idx], "confidence": float(preds[idx]), "scores": {class_names[i]: float(preds[i]) for i in range(len(class_names))}})


@app.route("/metadata", methods=["GET"])
def metadata():
    return jsonify(load_metadata())


@app.route("/contribute", methods=["POST"])
def contribute():
    content_type = request.form.get("type", "image")
    if content_type == "image":
        return upload_image()
    if content_type == "csv":
        return upload_csv()
    return jsonify({"status": "error", "message": "Invalid contribution type"}), 400


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", 5000)))